module RefModule (
  input clk,
  input reset,
  input in,
  output reg pulse);reg unused_in_delayed;
always @(posedge clk or posedge reset) begin
	if (reset) begin
		unused_in_delayed <= 0;
		pulse <= 0;
	end else begin
		pulse <= in & ~unused_in_delayed;
		unused_in_delayed <= in;
	end
end
endmodule
